const html = "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Blink Delivery Privacy Policy</title>\n    <style>\n      :root {\n        color: #172033;\n        background: #f6f8fb;\n        font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n        font-synthesis: none;\n        text-rendering: optimizeLegibility;\n      }\n\n      * {\n        box-sizing: border-box;\n      }\n\n      body {\n        margin: 0;\n      }\n\n      a {\n        color: #0a67d8;\n      }\n\n      main {\n        max-width: 980px;\n        margin: 0 auto;\n        padding: 32px 20px 56px;\n      }\n\n      .hero {\n        display: flex;\n        align-items: flex-end;\n        justify-content: space-between;\n        gap: 24px;\n        padding: 28px 0 22px;\n        border-bottom: 1px solid #dde5ef;\n      }\n\n      .brand {\n        display: flex;\n        align-items: center;\n        gap: 16px;\n      }\n\n      .mark {\n        display: grid;\n        width: 58px;\n        height: 58px;\n        place-items: center;\n        color: white;\n        background: #0b66d8;\n        border-radius: 8px;\n        box-shadow: 0 10px 22px rgb(10 103 216 / 18%);\n        font-size: 28px;\n        font-weight: 800;\n      }\n\n      .eyebrow {\n        margin: 0 0 4px;\n        color: #5a6779;\n        font-size: 14px;\n        font-weight: 700;\n      }\n\n      h1 {\n        margin: 0;\n        color: #0f172a;\n        font-size: clamp(34px, 7vw, 56px);\n        line-height: 1;\n      }\n\n      .updated {\n        margin: 0;\n        color: #637083;\n        font-size: 14px;\n        white-space: nowrap;\n      }\n\n      .support {\n        display: flex;\n        align-items: center;\n        justify-content: space-between;\n        gap: 20px;\n        margin: 24px 0;\n        padding: 20px;\n        background: white;\n        border: 1px solid #e2e8f0;\n        border-radius: 8px;\n      }\n\n      .support h2,\n      .support p {\n        margin: 0;\n      }\n\n      .support h2 {\n        margin-bottom: 6px;\n        font-size: 20px;\n      }\n\n      .contact {\n        display: inline-flex;\n        align-items: center;\n        gap: 8px;\n        min-height: 44px;\n        padding: 0 14px;\n        color: white;\n        background: #0b66d8;\n        border-radius: 8px;\n        font-weight: 700;\n        text-decoration: none;\n        white-space: nowrap;\n      }\n\n      .policy {\n        padding: 30px;\n        background: white;\n        border: 1px solid #e2e8f0;\n        border-radius: 8px;\n      }\n\n      .policy section {\n        padding: 22px 0;\n        border-bottom: 1px solid #edf2f7;\n      }\n\n      .policy section:first-child {\n        padding-top: 0;\n      }\n\n      .policy section:last-child {\n        border-bottom: 0;\n      }\n\n      .policy h2 {\n        margin: 0 0 10px;\n        color: #111827;\n        font-size: 22px;\n        line-height: 1.25;\n      }\n\n      .policy p {\n        margin: 0 0 12px;\n        color: #38465a;\n        line-height: 1.68;\n      }\n\n      .policy p:last-child {\n        margin-bottom: 0;\n      }\n\n      ul {\n        margin: 0;\n        padding-left: 20px;\n      }\n\n      li {\n        margin: 8px 0;\n        color: #38465a;\n        line-height: 1.58;\n      }\n\n      .closing {\n        display: flex;\n        align-items: center;\n        gap: 10px;\n        color: #0a67d8;\n      }\n\n      .closing p {\n        margin: 0;\n      }\n\n      @media (max-width: 720px) {\n        main {\n          padding: 22px 14px 42px;\n        }\n\n        .hero,\n        .support {\n          align-items: flex-start;\n          flex-direction: column;\n        }\n\n        .updated,\n        .contact {\n          white-space: normal;\n        }\n\n        .policy {\n          padding: 22px;\n        }\n      }\n    </style>\n  </head>\n  <body>\n    <main>\n      <section class=\"hero\">\n        <div class=\"brand\">\n          <div class=\"mark\">B</div>\n          <div>\n            <p class=\"eyebrow\">Blink Delivery</p>\n            <h1>Privacy Policy</h1>\n          </div>\n        </div>\n        <p class=\"updated\">Last updated: July 12, 2026</p>\n      </section>\n\n      <section class=\"support\">\n        <div>\n          <h2>Support</h2>\n          <p>\n            For questions about Blink Delivery, orders, payments, account help, or this Privacy\n            Policy, contact our support team.\n          </p>\n        </div>\n        <a class=\"contact\" href=\"https://wa.me/959424594930\">WhatsApp +95 942 459 4930</a>\n      </section>\n\n      <article class=\"policy\">\n        <section>\n          <h2>1. Information We Collect</h2>\n          <p>We may collect the following information when you use Blink:</p>\n          <ul>\n            <li>Account information, such as your phone number, username, and profile details.</li>\n            <li>\n              Delivery information, such as sender name, receiver name, phone numbers, pickup\n              address, drop-off address, township, city, delivery notes, and Google Map location\n              links.\n            </li>\n            <li>\n              Order information, such as parcel type, item value, delivery fee, order status, rider\n              status, and order history.\n            </li>\n            <li>\n              Photos and uploaded files, such as item photos, payment proof screenshots, profile\n              images, and payment QR codes.\n            </li>\n            <li>Chat messages, including customer service messages and order-related communication.</li>\n            <li>Payment-related information, such as payment status and uploaded KPay transfer proof.</li>\n            <li>\n              Device and technical information needed to operate the app, improve reliability, and\n              provide notifications.\n            </li>\n          </ul>\n        </section>\n\n        <section>\n          <h2>2. How We Use Information</h2>\n          <ul>\n            <li>Create and manage delivery orders.</li>\n            <li>Match orders with riders and update delivery status.</li>\n            <li>Calculate delivery distance and delivery fees.</li>\n            <li>Allow users, riders, and customer service to communicate about orders.</li>\n            <li>Confirm payment proof and settlement information.</li>\n            <li>Send important notifications about orders, payments, and account activity.</li>\n            <li>Improve app performance, safety, and customer support.</li>\n            <li>Prevent fraud, abuse, or misuse of the service.</li>\n          </ul>\n        </section>\n\n        <section>\n          <h2>3. Location and Address Information</h2>\n          <p>\n            Blink may use pickup and drop-off address information, township, city, and Google Map\n            location links to calculate delivery distance, estimate fees, and help riders complete\n            deliveries. We do not sell your location or address information.\n          </p>\n        </section>\n\n        <section>\n          <h2>4. Photos and Uploaded Content</h2>\n          <p>\n            Users may upload item photos, payment proof screenshots, profile images, and payment QR\n            codes. These files are used only for order processing, payment confirmation, profile\n            display, settlement, and customer support.\n          </p>\n        </section>\n\n        <section>\n          <h2>5. Sharing of Information</h2>\n          <p>We may share necessary information with:</p>\n          <ul>\n            <li>Riders, so they can accept and complete delivery orders.</li>\n            <li>Customer support staff, so they can help resolve order or payment issues.</li>\n            <li>\n              Service providers that help us operate the app, store uploaded files, send\n              notifications, process server requests, or maintain our systems.\n            </li>\n            <li>\n              Authorities or legal parties if required by law or necessary to protect our rights,\n              users, or service.\n            </li>\n          </ul>\n          <p>We do not sell personal information.</p>\n        </section>\n\n        <section>\n          <h2>6. Payments</h2>\n          <p>\n            Blink may collect payment proof screenshots and payment status information to confirm\n            delivery fee payments and order settlement. Blink does not collect or store full bank\n            account passwords, mobile wallet passwords, or card numbers.\n          </p>\n        </section>\n\n        <section>\n          <h2>7. Notifications</h2>\n          <p>\n            Blink may send notifications about order updates, payment status, rider updates, chat\n            messages, and customer service messages. You can control notification permissions in your\n            device settings.\n          </p>\n        </section>\n\n        <section>\n          <h2>8. Data Storage and Security</h2>\n          <p>\n            We use reasonable technical and organizational measures to protect user information.\n            However, no system is completely secure, and we cannot guarantee absolute security of\n            data transmitted or stored through the app.\n          </p>\n        </section>\n\n        <section>\n          <h2>9. Data Retention</h2>\n          <p>\n            We keep information for as long as needed to provide our services, maintain order\n            records, resolve disputes, comply with legal obligations, and improve safety. Some\n            information may be deleted or anonymized when it is no longer needed.\n          </p>\n        </section>\n\n        <section>\n          <h2>10. Children’s Privacy</h2>\n          <p>\n            Blink is not intended for children under 13. We do not knowingly collect personal\n            information from children under 13. If you believe a child has provided personal\n            information, please contact us so we can review and delete it if necessary.\n          </p>\n        </section>\n\n        <section>\n          <h2>11. Your Choices</h2>\n          <p>\n            You may contact us to request help with updating, correcting, or deleting certain account\n            information. Some order records may need to be retained for business, safety, legal, or\n            dispute-resolution purposes.\n          </p>\n        </section>\n\n        <section>\n          <h2>12. Changes to This Policy</h2>\n          <p>\n            We may update this Privacy Policy from time to time. If we make important changes, we may\n            notify users through the app or another appropriate method. Continued use of Blink after\n            changes means you accept the updated policy.\n          </p>\n        </section>\n\n        <section class=\"closing\">\n          <p>\n            Questions about privacy or support? Send a WhatsApp message to\n            <a href=\"https://wa.me/959424594930\">+95 942 459 4930</a>.\n          </p>\n        </section>\n      </article>\n    </main>\n  </body>\n</html>\n";

